// Target keywords for TotalGuard Yard Care
// Core service keywords + city variants across 12 service areas
const coreKeywords = [
  'lawn care',
  'lawn mowing',
  'fertilization service',
  'lawn fertilization',
  'weed control',
  'aeration and overseeding',
  'lawn aeration',
  'spring lawn care',
  'fall lawn care',
  'yard maintenance',
  'grass cutting service',
  'lawn treatment',
  'snow removal',
  'landscaping'
];

// 12 TotalGuard service areas
const cities = [
  'madison wi',
  'sun prairie wi',
  'middleton wi',
  'fitchburg wi',
  'verona wi',
  'waunakee wi',
  'deforest wi',
  'monona wi',
  'mcfarland wi',
  'cottage grove wi',
  'cross plains wi',
  'oregon wi'
];

// Build keyword list: core x city combos + generic near-me + brand
const keywords = [];
for (const kw of coreKeywords) {
  for (const city of cities) {
    keywords.push(`${kw} ${city}`);
  }
}
// Add generic near-me terms
keywords.push('lawn care near me');
keywords.push('lawn mowing service near me');
keywords.push('yard care near me');
keywords.push('best lawn care madison wi');
keywords.push('affordable lawn care madison');
keywords.push('commercial lawn care madison wi');
keywords.push('lawn care service dane county');
keywords.push('organic lawn care madison wi');
keywords.push('totalguard yard care');

// GSC data lag: use same date range as TG-96
const syncDate = new Date(Date.now() - 2 * 24 * 60 * 60 * 1000)
  .toISOString().split('T')[0];

return [{ json: { keywords, keywordCount: keywords.length, syncDate } }];

// Match target keywords against GSC data and build seo_rankings rows
const keywords = $('Define Target Keywords').first().json.keywords;
const syncDate = $('Define Target Keywords').first().json.syncDate;
const gscRows = $input.first().json || [];

// Build lookup map from GSC data (query -> row)
const gscMap = new Map();
const dataArray = Array.isArray(gscRows) ? gscRows : (gscRows.body || []);
for (const row of dataArray) {
  if (row.query) {
    gscMap.set(row.query.toLowerCase(), row);
  }
}

const rankings = keywords.map(kw => {
  const match = gscMap.get(kw.toLowerCase());
  return {
    keyword: kw,
    position: match ? Math.round(match.position * 100) / 100 : null,
    clicks: match ? (match.clicks || 0) : 0,
    impressions: match ? (match.impressions || 0) : 0,
    date: syncDate
  };
});

// Filter to only keywords that have GSC data (position != null)
const withData = rankings.filter(r => r.position !== null);
const withoutData = rankings.filter(r => r.position === null);

return [{ json: {
  upsertData: withData,
  trackedCount: withData.length,
  missingCount: withoutData.length,
  missingKeywords: withoutData.map(r => r.keyword),
  syncDate
}}];
